通过 `Get()` 直接获取音频管理器，虽然很方便但是也将 Enemy 和音频管理器绑死了。

```cpp
class IAudioManage
{
public:
    virtual ~IAudioManage() = delete;
    virtual void playSound(const std::string& name) = 0;
};

class Enemy
{
public:
    explicit Enemy(const& audiomanage)
        : audiomanage_(audiomanage)
    {
    }
private:
    IAudioManage& audiomanage_;
};
```
依赖注入版本，不再依赖某个Manage，而是一个抽象接口，这个构造函数要求Enemy构造时必须传入一个audiomanage。

```cpp
class Singleton
{
public:
    static Singleton& Get()
    {
        static Singleton instance;
        return instance;
    }

    Singleton(const Singleton&) = delete;
    Singleton& operator=(const Singleton&) = delete;
    Singleton(Singleton&&) = delete;
    Singleton& operator=(Singleton&&) = delete;

private:
    Singleton() = default;
    ~Singleton() = default;
};
```

```cpp
class Singleton
{
public:
    static Singleton* Get()
    {
        if (instance_ == nullptr)
        {
            std::lock_guard<std::mutex> lock(mutex_);

            if (instance_ == nullptr)
            {
                instance_ = new Singleton();
            }
        }

        return instance_;
    }

private:
    Singleton() = default;

    static Singleton* instance_;
    static std::mutex mutex_;
};
```

